#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 c =vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;
float ang_hq = -atan(c.x,c.y)*q27;
float rad_hq = log(length(c));
vec2 uv2 =vec2((ang_hq + rad_hq*q24*0.4 + q23)/asin(1)*2, rad_hq*q26-q25 - sin(ang_hq*20)*(q28*0.15-0.03)-q28*0.4);
vec2 uv3 =vec2((ang_hq - rad_hq*q24*0.2 - q23)/asin(1)*2, rad_hq*0.4+q25*0.5 + sin(ang_hq*24)*(q28*0.4-0.04)-q28*0.2);

vec2 uv1 = (vUv-0.5)*uAspect.xy;

float rad2 = length(uv1) + .05;
float rad1 = .1/rad2 ;



vec3 crisp = GetPixel(fract(uv2)) + 2*GetPixel(fract(uv3));
crisp += 2*GetBlur2(fract(uv2)) + 2*GetBlur2(fract(uv3));

vec3 lay1 = vec3 (1,0,1)*vUv.y*pow(1-vRadius,8);

crisp = 3*crisp * pow(vRadius,1);

float mask = clamp01(1-4*vRadius);

ret = crisp + lay1*mask + mask * GetPixel(fract(vUv));


vUv = (vUv-.5)* uAspect.xy + .5;
vec2 uvX = 1-vUv;

vec3 retX0 = texture(sampler_main,vUv) +2*GetBlur2 (vUv);
vec3 retX1 = texture(sampler_main,uvX) + 2*GetBlur2 (uvX);
retX0 += q26;
retX0 += q26;



vec3 retZ1 = retX0 + retX1  ;
vec3 retZ2 = retX0 * retX1  ;
vec3 retMIX1 = mix(retZ2, retZ1, q29 * .16);

ret = mix(ret,retMIX1,q29 * .02);

vec3 retI = 1 - ret;
//retI += .2;
//ret -= .2;
if(q29 > 0){
 zz = q29;
}
//ret =  mix(ret,retI,sin(uTime)*(zz));
//vec3 retN1 = mix(ret,retI,sin(uTime)*(zz));
vec3 retFIX =  mix(ret,retI,(q29*ret*(vRadius * (2-q29)*((q26*q25)*.9*vRadius))));

//ret = mix(ret,retN1,sin(uTime));
//ret = mix(ret,retI,((q29 * (vRadius*vRadius))*((26*25)*.001)));
ret = mix(ret,retFIX,(q29*vRadius));
ret *= (ret + (audioHigh * q29));//*q25);
//ret += .1;
ret = mix(ret,ret.zxy,q28);
//ret = GetPixel(uv2);

  fragColor = ret;
}
